hook.real_world_problem:
Flipkart sale day at midnight. The 'Big Billion Day' banner cache expires simultaneously for millions of users:

```
T=0:00:00 — TTL expires for 'homepage::deals'
T=0:00:00 — 50,000 users load the homepage simultaneously
T=0:00:00 — ALL 50,000 find cache MISS
T=0:00:00 — ALL 50,000 query PostgreSQL for the same data
T=0:00:01 — PostgreSQL connection pool exhausted (pool=20)
T=0:00:01 — 49,980 requests queue, timeout, 503 errors
T=0:00:02 — Site appears DOWN for 2 seconds
```

**This is the cache stampede (thundering herd) problem.**

```java
// BROKEN: every miss queries DB
@Cacheable(value="deals", key="#date")
public List<Deal> getDeals(LocalDate date) {
    return dealRepo.findByDate(date);  // 50,000 concurrent hits!
}

// FIX 1: Mutex lock — only ONE thread rebuilds the cache:
public List<Deal> getDealsWithMutex(LocalDate date) {
    String key = "deals::" + date;
    List<Deal> cached = getFromRedis(key);
    if (cached != null) return cached;

    // Try to acquire a short-lived lock:
    String lockKey = key + "::lock";
    Boolean locked = redisTemplate.opsForValue()
        .setIfAbsent(lockKey, "1", Duration.ofSeconds(10));  // SETNX

    if (Boolean.TRUE.equals(locked)) {
        // WE hold the lock — query DB and fill cache:
        List<Deal> fresh = dealRepo.findByDate(date);
        storeInRedis(key, fresh, Duration.ofMinutes(10));
        redisTemplate.delete(lockKey);
        return fresh;
    } else {
        // Another thread is rebuilding — wait briefly + return stale:
        Thread.sleep(50);
        return getFromRedis(key);
    }
}
```

One pattern, thousands fewer failed requests during your next sale.

concept_explanation.cache_aside_manual:
**Manual cache-aside with RedisTemplate:**

```java
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.Optional;

@Service
public class ProductCacheService {
    private static final String PREFIX = "product:";
    private static final Duration TTL = Duration.ofMinutes(10);

    private final RedisTemplate<String, Object> redisTemplate;
    private final ProductRepository productRepo;

    // Manual cache-aside pattern:
    public Optional<Product> findById(String id) {
        String key = PREFIX + id;  // 'product:P001'

        // 1. Check cache:
        Object cached = redisTemplate.opsForValue().get(key);
        if (cached != null) {
            return Optional.of((Product) cached);  // CACHE HIT
        }

        // 2. Cache miss — query DB:
        Optional<Product> product = productRepo.findById(id);

        // 3. Store in cache (with TTL):
        product.ifPresent(p -> redisTemplate.opsForValue().set(key, p, TTL));

        return product;
    }

    // Write-through: update both DB and cache:
    public Product save(Product product) {
        Product saved = productRepo.save(product);
        String key = PREFIX + saved.getId();
        redisTemplate.opsForValue().set(key, saved, TTL);
        return saved;
    }

    // Cache aside on delete:
    public void delete(String id) {
        productRepo.deleteById(id);
        redisTemplate.delete(PREFIX + id);
    }

    // Null object pattern — cache 'not found' to avoid DB hits for missing keys:
    private static final String NULL_SENTINEL = "__NULL__";

    public Optional<Product> findByIdWithNullCache(String id) {
        String key = PREFIX + id;
        Object cached = redisTemplate.opsForValue().get(key);

        if (NULL_SENTINEL.equals(cached)) {
            return Optional.empty();  // cached 'not found'
        }
        if (cached != null) {
            return Optional.of((Product) cached);
        }

        Optional<Product> result = productRepo.findById(id);
        if (result.isPresent()) {
            redisTemplate.opsForValue().set(key, result.get(), TTL);
        } else {
            // Cache the miss with SHORT TTL (1 min) to prevent repeated DB hits:
            redisTemplate.opsForValue().set(key, NULL_SENTINEL, Duration.ofMinutes(1));
        }
        return result;
    }
}
```

concept_explanation.redis_hash:
**Redis Hash — store structured objects efficiently:**

```java
// Redis Hash: store multiple fields for one key
// Like a Map<String, String> stored at a single Redis key
// Efficient: HGET instead of GET + JSON parse for individual fields

@Service
public class UserProfileService {
    private final RedisTemplate<String, String> stringRedisTemplate;

    private String hashKey(String userId) { return "user:profile:" + userId; }

    // Store profile fields as Redis Hash:
    public void cacheProfile(UserProfile profile) {
        String key = hashKey(profile.getUserId());
        Map<String, String> fields = Map.of(
            "name",     profile.getName(),
            "email",    profile.getEmail(),
            "city",     profile.getCity(),
            "plan",     profile.getPlan()
        );
        stringRedisTemplate.opsForHash().putAll(key, fields);
        stringRedisTemplate.expire(key, Duration.ofHours(1));
        // Redis: HSET user:profile:U001 name 'Aisha' email 'aisha@...' city 'Mumbai' plan 'Pro'
    }

    // Get full profile:
    public Optional<UserProfile> getProfile(String userId) {
        String key = hashKey(userId);
        Map<Object, Object> fields = stringRedisTemplate.opsForHash().entries(key);
        if (fields.isEmpty()) return Optional.empty();

        return Optional.of(new UserProfile(
            userId,
            (String) fields.get("name"),
            (String) fields.get("email"),
            (String) fields.get("city"),
            (String) fields.get("plan")
        ));
    }

    // Update single field (no need to re-cache entire object):
    public void updateCity(String userId, String newCity) {
        // HSET user:profile:U001 city 'Delhi'
        stringRedisTemplate.opsForHash().put(hashKey(userId), "city", newCity);
    }

    // Get single field (HGET — more efficient than GET + parse):
    public String getPlan(String userId) {
        return (String) stringRedisTemplate.opsForHash()
            .get(hashKey(userId), "plan");
    }
}
```

concept_explanation.sorted_set_leaderboard:
**Redis Sorted Set — real-time leaderboard:**

```java
// Sorted Set: members with scores, kept in sorted order
// Operations: ZADD, ZRANK, ZREVRANK, ZRANGE, ZINCRBY — all O(log N)

@Service
public class LeaderboardService {
    private final RedisTemplate<String, String> redis;

    private static final String BOARD = "leaderboard:traders";

    // Record a trade profit:
    public void recordProfit(String traderId, double profit) {
        // ZINCRBY leaderboard:traders +profit traderId
        redis.opsForZSet().incrementScore(BOARD, traderId, profit);
    }

    // Get rank (0-indexed, highest score first):
    public Long getRank(String traderId) {
        // ZREVRANK: rank from highest → lowest
        return redis.opsForZSet().reverseRank(BOARD, traderId);
        // Returns 0 for #1, 1 for #2, null if not in leaderboard
    }

    // Get top N traders:
    public List<String> getTopN(int n) {
        // ZREVRANGE: returns members from highest to lowest score
        var topSet = redis.opsForZSet().reverseRange(BOARD, 0, n - 1);
        return topSet != null ? new ArrayList<>(topSet) : List.of();
    }

    // Get trader's current score:
    public double getScore(String traderId) {
        Double score = redis.opsForZSet().score(BOARD, traderId);
        return score != null ? score : 0.0;
    }

    // Get top N with scores:
    public List<Map<String, Object>> getTopNWithScores(int n) {
        var topWithScores = redis.opsForZSet()
            .reverseRangeWithScores(BOARD, 0, n - 1);
        if (topWithScores == null) return List.of();

        return topWithScores.stream()
            .map(entry -> Map.of(
                "traderId", entry.getValue(),
                "profit",   entry.getScore()
            ))
            .collect(java.util.stream.Collectors.toList());
    }

    // Reset leaderboard at end of day:
    public void resetLeaderboard() {
        redis.delete(BOARD);
    }
}
```

concept_explanation.cache_stampede:
**Cache stampede prevention:**

```java
// PROBLEM: When a popular cache key expires, thousands of threads
// all miss simultaneously and all query the DB.

// SOLUTION 1: Mutex lock (SETNX pattern):
@Service
public class StampedeSafeService {
    private final RedisTemplate<String, Object> redis;
    private final DealRepository dealRepo;

    @SuppressWarnings("unchecked")
    public List<Deal> getDeals(String city) {
        String key  = "deals:" + city;
        String lock = key + ":lock";

        // Fast path: try cache first
        Object cached = redis.opsForValue().get(key);
        if (cached != null) return (List<Deal>) cached;

        // Slow path: acquire lock to rebuild
        Boolean acquired = redis.opsForValue()
            .setIfAbsent(lock, "1", Duration.ofSeconds(10));

        if (Boolean.TRUE.equals(acquired)) {
            try {
                // Double-check: another thread may have filled cache while we acquired lock
                Object refetch = redis.opsForValue().get(key);
                if (refetch != null) return (List<Deal>) refetch;

                // We own the lock — build the cache:
                List<Deal> fresh = dealRepo.findByCity(city);
                redis.opsForValue().set(key, fresh, Duration.ofMinutes(5));
                return fresh;
            } finally {
                redis.delete(lock);
            }
        } else {
            // Another thread is building — wait briefly, return stale or empty:
            try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            Object refetch = redis.opsForValue().get(key);
            return refetch != null ? (List<Deal>) refetch : dealRepo.findByCity(city);
        }
    }

    // SOLUTION 2: Serve stale while revalidating (background refresh):
    // Keep the stale entry alive, trigger async refresh before TTL expires
    // → users always get a response, never a miss penalty
    // Implementation: @Scheduled job refreshes before TTL expires
}
```

