```java
@Service
public class InstrumentCacheService {
    private final RedisTemplate<String, Object> redis;
    private final InstrumentRepository repo;
    private static final String NULL_MARKER = "__NONE__";

    public Optional<Instrument> findBySymbol(String symbol) {
        String key = "instrument:" + symbol;
        Object cached = redis.opsForValue().get(key);

        if (NULL_MARKER.equals(cached))  return Optional.empty();  // cached miss
        if (cached instanceof Instrument i) return Optional.of(i); // cache hit

        Optional<Instrument> result = repo.findBySymbol(symbol);
        if (result.isPresent()) {
            redis.opsForValue().set(key, result.get(), Duration.ofHours(6));
        } else {
            redis.opsForValue().set(key, NULL_MARKER, Duration.ofMinutes(5));
        }
        return result;
    }
}
